import{_ as l,c as e,o,ae as t}from"./chunks/framework.CDjunVez.js";const c=JSON.parse('{"title":"18 人團隊、800 萬用戶、18 億美元估值：Lovable 為何要買一家雲端公司？","description":"一家成立才一年的 AI 新創，以驚人速度成長為獨角獸，卻在此刻選擇收購一家歐洲雲端服務商。這背後藏著什麼樣的商業邏輯？","frontmatter":{"title":"18 人團隊、800 萬用戶、18 億美元估值：Lovable 為何要買一家雲端公司？","description":"一家成立才一年的 AI 新創，以驚人速度成長為獨角獸，卻在此刻選擇收購一家歐洲雲端服務商。這背後藏著什麼樣的商業邏輯？","date":"2025-11-25T00:00:00.000Z","author":"Clement Tang","tags":["Lovable","Molnett","AI編碼","併購","社群貼文"],"category":"articles","status":"published","lastModified":"2026-01-27T00:00:00.000Z"},"headers":[],"relativePath":"articles/2025-11-25-lovable-acquires-molnett-social.md","filePath":"articles/2025-11-25-lovable-acquires-molnett-social.md"}'),r={name:"articles/2025-11-25-lovable-acquires-molnett-social.md"};function i(p,a,n,h,s,b){return o(),e("div",null,[...a[0]||(a[0]=[t('<h1 id="_18-人團隊、800-萬用戶、18-億美元估值-lovable-為何要買一家雲端公司" tabindex="-1">18 人團隊、800 萬用戶、18 億美元估值：Lovable 為何要買一家雲端公司？ <a class="header-anchor" href="#_18-人團隊、800-萬用戶、18-億美元估值-lovable-為何要買一家雲端公司" aria-label="Permalink to &quot;18 人團隊、800 萬用戶、18 億美元估值：Lovable 為何要買一家雲端公司？&quot;">​</a></h1><blockquote><p>一家成立才一年的 AI 新創，以驚人速度成長為獨角獸，卻在此刻選擇收購一家歐洲雲端服務商。這背後藏著什麼樣的商業邏輯？</p></blockquote><hr><h2 id="一年從零到獨角獸-然後呢" tabindex="-1">一年從零到獨角獸，然後呢？ <a class="header-anchor" href="#一年從零到獨角獸-然後呢" aria-label="Permalink to &quot;一年從零到獨角獸，然後呢？&quot;">​</a></h2><p>2024 年 11 月，瑞典新創 Lovable 正式上線。</p><p>這是一個讓「不會寫程式的人也能開發應用程式」的 AI 平台。你只需要用自然語言描述想要什麼，AI 就能幫你寫出程式碼、建立應用。</p><p><strong>然後，奇蹟發生了。</strong></p><p>上線 4 週，年化營收達到 400 萬美元。8 個月後，Lovable 拿到 2 億美元 A 輪融資，估值 18 億美元，成為獨角獸。到了 2025 年 11 月，用戶數逼近 800 萬，年化營收突破 1.2 億美元。</p><p>更驚人的是：整個公司只有 18 個人。</p><p>這種成長速度，即使在 AI 產業也是罕見的。但就在所有人以為 Lovable 會繼續加速衝刺時，他們做了一個意外的決定——</p><p><strong>收購一家歐洲雲端服務商 Molnett。</strong></p><p>不是募資，不是擴張市場，而是買下一家雲端基礎設施公司。</p><p>為什麼？</p><hr><h2 id="當成長太快-基礎設施跟不上" tabindex="-1">當成長太快，基礎設施跟不上 <a class="header-anchor" href="#當成長太快-基礎設施跟不上" aria-label="Permalink to &quot;當成長太快，基礎設施跟不上&quot;">​</a></h2><p>Lovable 的 CTO Fabian Hedin 給出了答案：「<strong>Molnett 帶來了世界上最有才華的基礎設施工程師。</strong>」</p><p>這句話透露了關鍵訊息。</p><p>當一家公司在一年內從 0 成長到 800 萬用戶，背後需要什麼？不只是好產品，還要有強大的基礎設施來支撐。</p><h3 id="成長的代價" tabindex="-1">成長的代價 <a class="header-anchor" href="#成長的代價" aria-label="Permalink to &quot;成長的代價&quot;">​</a></h3><p>Lovable 的快速擴張並非毫無代價。報導指出，他們曾經：</p><ul><li><strong>緊急進行語言遷移</strong>：從 Python 重寫成 Go，以提升性能</li><li><strong>與第三方雲端服務合作</strong>：在 fly.io 上託管超過 4,000 個持續運行的實例</li><li><strong>面臨穩定性問題</strong>：超高速成長帶來的技術壓力</li></ul><p>這些都是「成長太快」的訊號。</p><p>當你有 18 個人要服務 800 萬用戶，你需要的不只是更多產品經理或業務人員——你需要能夠設計和維護大規模基礎設施的頂尖工程師。</p><p>而這種人才，全球都在搶。</p><hr><h2 id="收購團隊比招募更快" tabindex="-1">收購團隊比招募更快 <a class="header-anchor" href="#收購團隊比招募更快" aria-label="Permalink to &quot;收購團隊比招募更快&quot;">​</a></h2><p>科技業有個不成文的規則：<strong>當你需要一整個團隊的專業能力，收購比招募快得多。</strong></p><p>Molnett 花了數年時間建立的能力包括：</p><ul><li>在瑞典運營的數據中心</li><li>安全、可擴展的 serverless 平台</li><li>支援多種程式語言的容器化部署</li><li>符合歐盟嚴格隱私法規的架構</li></ul><p>更重要的是：<strong>一個經驗豐富、配合默契的工程團隊。</strong></p><p>如果 Lovable 選擇自己招募，可能需要：</p><ol><li>花 6-12 個月找到合適的人才</li><li>再花 6-12 個月讓團隊磨合</li><li>從零開始設計和建立基礎設施</li></ol><p>但透過收購 Molnett，他們一次解決了所有問題。</p><p>這就是為什麼 Fabian Hedin 強調的是「人才」，而不只是「技術」。</p><hr><h2 id="ai-編碼平台的新戰場-從開發到部署" tabindex="-1">AI 編碼平台的新戰場：從開發到部署 <a class="header-anchor" href="#ai-編碼平台的新戰場-從開發到部署" aria-label="Permalink to &quot;AI 編碼平台的新戰場：從開發到部署&quot;">​</a></h2><p>Lovable 的收購決策還透露了另一個重要趨勢：<strong>AI 編碼平台的競爭重點正在改變。</strong></p><h3 id="第一階段-比誰的-ai-更聰明" tabindex="-1">第一階段：比誰的 AI 更聰明 <a class="header-anchor" href="#第一階段-比誰的-ai-更聰明" aria-label="Permalink to &quot;第一階段：比誰的 AI 更聰明&quot;">​</a></h3><p>早期的 AI 編碼工具競爭焦點很單純：</p><ul><li>誰的 AI 能寫出更好的程式碼？</li><li>誰能支援更多程式語言？</li><li>誰的介面更好用？</li></ul><p>Cursor、Replit、GitHub Copilot、v0.dev 都在這個戰場上廝殺。</p><h3 id="第二階段-誰能提供完整體驗" tabindex="-1">第二階段：誰能提供完整體驗 <a class="header-anchor" href="#第二階段-誰能提供完整體驗" aria-label="Permalink to &quot;第二階段：誰能提供完整體驗&quot;">​</a></h3><p>但現在，問題變了。</p><p>用戶發現：「我可以用 AI 寫出程式碼，然後呢？」</p><p>部署到哪裡？如何擴展？怎麼維護？</p><p><strong>一個新創公司 Shuttle 在今年 10 月募資 600 萬美元，專門解決「AI 編碼的部署問題」，就是最好的證明。</strong></p><p>市場告訴所有 AI 編碼平台：光會寫程式碼已經不夠了，你需要提供從開發到部署的完整解決方案。</p><p>Lovable 顯然聽到了這個訊號。</p><p>透過整合 Molnett 的雲端基礎設施，他們能夠：</p><ul><li>讓用戶在同一個平台上完成開發和部署</li><li>減少對第三方雲端服務的依賴</li><li>提供更順暢的使用體驗</li><li>長期降低營運成本</li></ul><p>這就是「垂直整合」的價值。</p><hr><h2 id="歐洲雲端的理想與現實" tabindex="-1">歐洲雲端的理想與現實 <a class="header-anchor" href="#歐洲雲端的理想與現實" aria-label="Permalink to &quot;歐洲雲端的理想與現實&quot;">​</a></h2><p>這起併購還有一個值得關注的面向：<strong>Molnett 原本是帶著使命而生的。</strong></p><h3 id="對抗數位殖民化" tabindex="-1">對抗數位殖民化 <a class="header-anchor" href="#對抗數位殖民化" aria-label="Permalink to &quot;對抗數位殖民化&quot;">​</a></h3><p>Molnett 的創立願景是對抗「數位殖民化」。</p><p>他們的主張很簡單：</p><ul><li>歐洲企業的資料應該留在歐洲</li><li>不應該受制於美國的雲端巨頭（AWS、Azure、Google Cloud）</li><li>歐洲需要自己的主權雲端</li></ul><p>數據也支持他們的擔憂：過去五年，歐洲雲端市場成長了 6 倍，但歐洲本土供應商的市佔率卻從 26% 暴跌至 13%。</p><p>美國三大雲端巨頭掌握了 87% 的市場。</p><h3 id="理想敵不過市場力量" tabindex="-1">理想敵不過市場力量 <a class="header-anchor" href="#理想敵不過市場力量" aria-label="Permalink to &quot;理想敵不過市場力量&quot;">​</a></h3><p>但最終，Molnett 被 Lovable 收購了。</p><p>所有現有客戶將被協助轉移到其他服務商。Molnett 的平台將關閉，技術和團隊將整合進 Lovable。</p><p>這個結局或許有些諷刺：一家倡議歐洲數位主權的公司，最終成為一家快速成長的瑞典新創的一部分。</p><p>但這也反映了一個殘酷的現實：<strong>在雲端市場，理想和技術不足以對抗規模經濟。</strong></p><p>歐洲政府和企業雖然口頭支持本土雲端服務，但實際採購時，仍然選擇 AWS、Azure、GCP。因為他們更便宜、更成熟、生態系更完整。</p><p>對 Molnett 的團隊來說，加入 Lovable 可能是讓他們的技術發揮更大價值的最佳選擇。</p><p>對歐洲數位主權來說，這又是一次挫敗。</p><hr><h2 id="獨角獸成長的三個隱藏成本" tabindex="-1">獨角獸成長的三個隱藏成本 <a class="header-anchor" href="#獨角獸成長的三個隱藏成本" aria-label="Permalink to &quot;獨角獸成長的三個隱藏成本&quot;">​</a></h2><p>Lovable 的故事很激勵人心，但也提醒我們：超高速成長是有代價的。</p><h3 id="_1-技術債累積" tabindex="-1">1. 技術債累積 <a class="header-anchor" href="#_1-技術債累積" aria-label="Permalink to &quot;1. 技術債累積&quot;">​</a></h3><p>當你用 4 週達到 400 萬美元 ARR，你沒有時間好好設計架構。</p><p>Lovable 的 Python 到 Go 的緊急遷移，就是典型的「先求有再求好」。</p><p>現在透過收購 Molnett，他們有機會重新打好基礎。</p><h3 id="_2-組織壓力巨大" tabindex="-1">2. 組織壓力巨大 <a class="header-anchor" href="#_2-組織壓力巨大" aria-label="Permalink to &quot;2. 組織壓力巨大&quot;">​</a></h3><p>18 個人服務 800 萬用戶，聽起來很有效率。</p><p>但換個角度想：每個人平均要服務超過 40 萬用戶。</p><p>這種壓力是不可持續的。收購團隊也是紓解組織壓力的方式。</p><h3 id="_3-依賴第三方風險" tabindex="-1">3. 依賴第三方風險 <a class="header-anchor" href="#_3-依賴第三方風險" aria-label="Permalink to &quot;3. 依賴第三方風險&quot;">​</a></h3><p>快速成長期，Lovable 依賴：</p><ul><li>OpenAI 和 Anthropic 的 LLM</li><li>fly.io 的雲端服務</li><li>各種第三方工具</li></ul><p>這些依賴在成長期是必要的，但長期來看會限制靈活性、增加成本。</p><p>透過收購自建基礎設施能力，Lovable 正在降低這些風險。</p><hr><h2 id="給創業者的三個啟示" tabindex="-1">給創業者的三個啟示 <a class="header-anchor" href="#給創業者的三個啟示" aria-label="Permalink to &quot;給創業者的三個啟示&quot;">​</a></h2><h3 id="啟示-1-產品成功後-基礎設施成為關鍵" tabindex="-1">啟示 1：產品成功後，基礎設施成為關鍵 <a class="header-anchor" href="#啟示-1-產品成功後-基礎設施成為關鍵" aria-label="Permalink to &quot;啟示 1：產品成功後，基礎設施成為關鍵&quot;">​</a></h3><p>Lovable 用一年證明了產品市場契合度。</p><p>但要從「成功的產品」變成「長期主導的平台」，基礎設施能力是必經之路。</p><p><strong>你的產品再好，如果系統常當機、速度慢、無法擴展，用戶還是會離開。</strong></p><h3 id="啟示-2-人才稀缺性決定收購價值" tabindex="-1">啟示 2：人才稀缺性決定收購價值 <a class="header-anchor" href="#啟示-2-人才稀缺性決定收購價值" aria-label="Permalink to &quot;啟示 2：人才稀缺性決定收購價值&quot;">​</a></h3><p>在 AI 時代，每個人都在談論資料科學家、AI 工程師的稀缺性。</p><p>但 Lovable 的選擇提醒我們：<strong>基礎設施工程師同樣極度稀缺。</strong></p><p>能設計和運營大規模分散式系統的人才，全球都在搶。</p><p>當你需要這種能力，收購一個成熟團隊可能比自己慢慢建立更有效率。</p><h3 id="啟示-3-垂直整合創造長期競爭力" tabindex="-1">啟示 3：垂直整合創造長期競爭力 <a class="header-anchor" href="#啟示-3-垂直整合創造長期競爭力" aria-label="Permalink to &quot;啟示 3：垂直整合創造長期競爭力&quot;">​</a></h3><p>AI 編碼市場現在很熱鬧，但最終贏家可能是那些能夠控制整個價值鏈的平台。</p><p>從開發、測試、部署、託管到維運——每個環節都無縫整合。</p><p>這需要技術深度，也需要資本。</p><p>Lovable 的 2.28 億美元融資讓他們有底氣進行這樣的投資。</p><hr><h2 id="下一步-從獨角獸到巨獸" tabindex="-1">下一步：從獨角獸到巨獸？ <a class="header-anchor" href="#下一步-從獨角獸到巨獸" aria-label="Permalink to &quot;下一步：從獨角獸到巨獸？&quot;">​</a></h2><p>Lovable 的故事還在繼續。</p><p>傳聞他們正在進行新一輪融資，估值可能達到 60 億美元——是現在的 3 倍多。</p><p>收購 Molnett 只是開始。</p><p>接下來，我們可能會看到：</p><ul><li>更多針對企業客戶的功能</li><li>自建雲端平台的逐步推出</li><li>可能的進一步收購</li><li>最終的 IPO</li></ul><p>但現在最值得觀察的問題是：<strong>他們能否成功整合 Molnett？</strong></p><p>整合團隊、整合技術、整合文化——這些都是併購後最大的挑戰。</p><p>如果成功，Lovable 將成為 AI 編碼領域最具競爭力的平台之一。</p><p>如果失敗，這次收購可能只是一個昂貴的教訓。</p><hr><h2 id="寫在最後-成長的藝術" tabindex="-1">寫在最後：成長的藝術 <a class="header-anchor" href="#寫在最後-成長的藝術" aria-label="Permalink to &quot;寫在最後：成長的藝術&quot;">​</a></h2><p>從 Lovable 併購 Molnett 這件事，我們看到了新創成長的多個面向：</p><p><strong>當你成長得太快，問題來得比成功更猛烈。</strong></p><p>技術債、組織壓力、基礎設施瓶頸——這些都是超高速成長的副作用。</p><p>但 Lovable 的做法值得參考：</p><ul><li>用募資換取時間和空間</li><li>透過收購快速補強弱點</li><li>在成長期就開始建立長期競爭力</li></ul><p>這或許就是成長的藝術：知道什麼時候該踩油門，什麼時候該打地基。</p><p><strong>最快的成長方式，往往是在關鍵時刻放慢腳步，把基礎打好。</strong></p><p>對 Lovable 來說，收購 Molnett 就是這樣的時刻。</p><p>對所有快速成長的新創來說，這個故事都值得深思。</p><hr><h2 id="關鍵數據一覽" tabindex="-1">關鍵數據一覽 <a class="header-anchor" href="#關鍵數據一覽" aria-label="Permalink to &quot;關鍵數據一覽&quot;">​</a></h2><p><strong>Lovable 成長軌跡：</strong></p><ul><li>上線 4 週：400 萬美元 ARR</li><li>8 個月：成為獨角獸（18 億美元估值）</li><li>1 年：800 萬用戶，1.2 億美元 ARR</li><li>團隊規模：18 人</li><li>總融資：2.28 億美元</li></ul><p><strong>Molnett 背景：</strong></p><ul><li>定位：歐洲主權雲端服務商</li><li>技術：Serverless 平台，瑞典數據中心</li><li>使命：對抗數位殖民化</li><li>結果：被 Lovable 收購，平台將關閉</li></ul><p><strong>產業趨勢：</strong></p><ul><li>歐洲本土雲端市佔率：26% → 13%（五年內）</li><li>美國三大雲端巨頭市佔率：87%</li><li>AI 編碼市場：從「工具」進化為「平台」</li></ul><hr><h2 id="參考資料" tabindex="-1">參考資料 <a class="header-anchor" href="#參考資料" aria-label="Permalink to &quot;參考資料&quot;">​</a></h2><ol><li><a href="https://lovable.dev/blog/lovable-welcomes-molnett" target="_blank" rel="noreferrer">Lovable acquires Molnett and expands our platform team - Lovable Blog</a></li><li><a href="https://news.ycombinator.com/item?id=46049357" target="_blank" rel="noreferrer">Lovable acquires cloud provider Molnett | Hacker News</a></li><li><a href="https://techcrunch.com/2025/07/17/lovable-becomes-a-unicorn-with-200m-series-a-just-8-months-after-launch/" target="_blank" rel="noreferrer">Lovable becomes a unicorn with $200M Series A | TechCrunch</a></li><li><a href="https://techcrunch.com/2025/11/10/lovable-says-its-nearing-8-million-users-as-the-year-old-ai-coding-startup-eyes-more-corporate-employees/" target="_blank" rel="noreferrer">Lovable nears 8 million users | TechCrunch</a></li><li><a href="https://getlatka.com/companies/lovable.dev" target="_blank" rel="noreferrer">How Lovable hit $200M revenue with 18 person team | Getlatka</a></li></ol><hr><h2 id="更新記錄" tabindex="-1">更新記錄 <a class="header-anchor" href="#更新記錄" aria-label="Permalink to &quot;更新記錄&quot;">​</a></h2><ul><li><strong>2025-11-25：</strong> 建立社群版本文章，以商業周刊風格改寫 Lovable 併購 Molnett 分析</li></ul><hr>',137)])])}const d=l(r,[["render",i]]);export{c as __pageData,d as default};
